class SessionManager:
    """Manages session tokens and timeouts."""

    SESSION_TIMEOUT_SECONDS = 3600  # 1 hour

    def __init__(self):
        self.sessions: Dict[str, Dict[str, Any]] = {}

    def create_session(self, username: str) -> str:
        """Generate a secure session token and store it."""
        token = secrets.token_urlsafe(32)
        self.sessions[token] = {
            'username': username,
            'created_at': time.time()
        }
        logger.info(f"Session created for user: {username}")
        return token

    def validate_session(self, token: str) -> Optional[str]:
        """Check if a session is valid and not expired."""
        if token not in self.sessions:
            return None

        session_data = self.sessions[token]
        if time.time() - session_data['created_at'] > self.SESSION_TIMEOUT_SECONDS:
            del self.sessions[token]
            logger.warning(f"Session expired for user: {session_data['username']}")
            return None

        return session_data['username']

    def invalidate_session(self, token: str) -> None:
        """Remove a session token."""
        if token in self.sessions:
            del self.sessions[token]
            logger.info(f"Session invalidated for user: {self.sessions[token]['username']}")

class UserDatabase:
    """Simulated database for user storage and password verification."""

    def __init__(self):
        # Simulated database: {username: hashed_password}
        self.users: Dict[str, str] = {}

    def add_user(self, username: str, password: str) -> None:
        """Add a new user to the database."""
        self.users[username] = self._hash_password(password)

    def get_user(self, username: str) -> Optional[str]:
        """Retrieve a user's hashed password."""
        return self.users.get(username)

    def _hash_password(self, password: str) -> str:
        """Hash a password using SHA-256 with a random salt."""
        salt = secrets.token_hex(16)
        hash_obj = hashlib.sha256((password + salt).encode('utf-8'))
        return f"{salt}:{hash_obj.hexdigest()}"

    def verify_password(self, username: str, password: str) -> bool:
        """Verify a password against the stored hash."""
        stored_hash = self.get_user(username)
        if not stored_hash:
            return False

        salt, stored_digest = stored_hash.split(':')
        hash_obj = hashlib.sha256((password + salt).encode('utf-8'))
        return hash_obj.hexdigest() == stored_digest

class UserAuthenticator:
    """Handles user authentication flow with validation and logging."""

    USERNAME_PATTERN = re.compile(r'^[a-zA-Z0-9]{3,20}$')
    MIN_PASSWORD_LENGTH = 8
    PASSWORD_PATTERN = re.compile(r'^(?=.*[A-Z])(?=.*\d).+$')

    def __init__(self, db: UserDatabase, session_manager: SessionManager):
        self.db = db
        self.session_manager = session_manager

    def _validate_username(self, username: str) -> bool:
        """Validate username format."""
        if not isinstance(username, str):
            return False
        return bool(self.USERNAME_PATTERN.match(username))

    def _validate_password(self, password: str) -> bool:
        """Validate password strength."""
        if not isinstance(password, str):
            return False
        if len(password) < self.MIN_PASSWORD_LENGTH:
            return False
        return bool(self.PASSWORD_PATTERN.match(password))

    def authenticate(self, username: str, password: str) -> Dict[str, Any]:
        """
        Execute the authentication flow.

        Returns:
            Dict with 'success' boolean and 'token' or 'error' message.
        """
        # Step 3: Validate username format
        if not self._validate_username(username):
            logger.error(f"Invalid username format: {username}")
            return {'success': False, 'error': 'Authentication Failed'}

        # Step 4: Validate password strength
        if not self._validate_password(password):
            logger.error(f"Invalid password strength for user: {username}")
            return {'success': False, 'error': 'Authentication Failed'}

        # Step 5: Check database for user
        stored_hash = self.db.get_user(username)
        if not stored_hash:
            logger.warning(f"User not found: {username}")
            return {'success': False, 'error': 'Authentication Failed'}

        # Step 6: Verify password hash
        if not self.db.verify_password(username, password):
            logger.warning(f"Password mismatch for user: {username}")
            return {'success': False, 'error': 'Authentication Failed'}

        # Step 7: Create session token
        token = self.session_manager.create_session(username)
        logger.info(f"Successful authentication for user: {username}")

        return {'success': True, 'token': token}

