"""
Log Rotation and Cleanup Script
Monitors, rotates, compresses, and cleans up application logs.
"""

import os
import sys
import gzip
import shutil
import time
from datetime import datetime, timedelta
from pathlib import Path

# Configuration
DEFAULT_LOG_DIR = "/var/log/app"
DEFAULT_MAX_SIZE_MB = 100
DEFAULT_RETENTION_DAYS = 30

def validate_path(path_str: str) -> Path:
    """Validates that the path is a directory and is writable."""
    try:
        path = Path(path_str)
        if not path.exists():
            print(f"Error: Directory '{path_str}' does not exist.")
            sys.exit(1)
        if not path.is_dir():
            print(f"Error: '{path_str}' is not a directory.")
            sys.exit(1)
        if not os.access(path, os.W_OK):
            print(f"Error: No write permission for directory '{path_str}'.")
            sys.exit(1)
        return path
    except Exception as e:
        print(f"Error validating path '{path_str}': {e}")
        sys.exit(1)

def validate_size(size_str: str) -> int:
    """Validates and converts size string to bytes."""
    try:
        size_str = size_str.strip().lower()
        if size_str.endswith('mb'):
            return int(float(size_str[:-2]) * 1024 * 1024)
        elif size_str.endswith('gb'):
            return int(float(size_str[:-2]) * 1024 * 1024 * 1024)
        elif size_str.endswith('kb'):
            return int(float(size_str[:-2]) * 1024)
        else:
            return int(size_str)
    except ValueError:
        print(f"Error: Invalid size format '{size_str}'. Use format like '100MB', '1GB', or integer bytes.")
        sys.exit(1)

def validate_days(days_str: str) -> int:
    """Validates retention days."""
    try:
        days = int(days_str)
        if days < 0:
            raise ValueError("Days cannot be negative.")
        return days
    except ValueError as e:
        print(f"Error: Invalid retention days '{days_str}'. {e}")
        sys.exit(1)

def get_log_files(directory: Path) -> list:
    """Retrieves all .log files in the directory."""
    try:
        return [f for f in directory.iterdir() if f.is_file() and f.suffix == '.log']
    except PermissionError:
        print(f"Error: Permission denied accessing files in '{directory}'.")
        sys.exit(1)

def rotate_log(log_file: Path) -> bool:
    """Rotates a single log file by renaming it with a timestamp."""
    try:
        timestamp = datetime.now().strftime("%Y%m%d_%H%M%S")
        rotated_name = f"{log_file.name}.{timestamp}"
        rotated_path = log_file.parent / rotated_name
        log_file.rename(rotated_path)
        # Create a new empty log file with same permissions if possible
        log_file.touch()
        print(f"Rotated: {log_file.name} -> {rotated_name}")
        return True
    except PermissionError:
        print(f"Error: Permission denied rotating '{log_file}'.")
        return False
    except Exception as e:
        print(f"Error rotating '{log_file}': {e}")
        return False

def compress_log(log_file: Path) -> bool:
    """Compresses a log file using gzip."""
    try:
        compressed_path = Path(str(log_file) + ".gz")
        with open(log_file, 'rb') as f_in:
            with gzip.open(compressed_path, 'wb') as f_out:
                shutil.copyfileobj(f_in, f_out)
        log_file.unlink()
        print(f"Compressed: {log_file.name} -> {compressed_path.name}")
        return True
    except PermissionError:
        print(f"Error: Permission denied compressing '{log_file}'.")
        return False
    except Exception as e:
        print(f"Error compressing '{log_file}': {e}")
        return False

def cleanup_old_logs(directory: Path, retention_days: int) -> int:
    """Deletes log files older than retention_days."""
    deleted_count = 0
    cutoff_time = datetime.now() - timedelta(days=retention_days)

    try:
        for file in directory.iterdir():
            if file.is_file() and (file.suffix == '.gz' or file.suffix == '.log'):
                try:
                    file_mtime = datetime.fromtimestamp(file.stat().st_mtime)
                    if file_mtime < cutoff_time:
                        file.unlink()
                        print(f"Deleted old log: {file.name}")
                        deleted_count += 1
                except FileNotFoundError:
                    continue
                except PermissionError:
                    print(f"Error: Permission denied deleting '{file}'.")
    except PermissionError:
        print(f"Error: Permission denied accessing directory '{directory}'.")

    return deleted_count

def main():
    # Parse arguments or use defaults
    log_dir = os.environ.get('LOG_DIR', DEFAULT_LOG_DIR)
    max_size_str = os.environ.get('MAX_SIZE', str(DEFAULT_MAX_SIZE_MB))
    retention_str = os.environ.get('RETENTION_DAYS', str(DEFAULT_RETENTION_DAYS))

    # Input Validation
    if len(sys.argv) >= 2:
        log_dir = sys.argv[1]
    if len(sys.argv) >= 3:
        max_size_str = sys.argv[2]
    if len(sys.argv) >= 4:
        retention_str = sys.argv[3]

    log_path = validate_path(log_dir)
    max_size_bytes = validate_size(max_size_str)
    retention_days = validate_days(retention_str)

    print(f"Starting Log Rotation Check.")
    print(f"Directory: {log_path}")
    print(f"Max Size Threshold: {max_size_bytes} bytes")
    print(f"Retention Period: {retention_days} days")

    log_files = get_log_files(log_path)

    if not log_files:
        print("No log files found to process.")
        return

    rotated_count = 0
    compressed_count = 0

    for log_file in log_files:
        try:
            file_size = log_file.stat().st_size
            if file_size >= max_size_bytes:
                if rotate_log(log_file):
                    rotated_count += 1
                    # Compress immediately after rotation if desired, 
                    # or compress all logs. Here we compress the rotated one.
                    if compress_log(log_file):
                        compressed_count += 1
        except Exception as e:
            print(f"Error processing '{log_file}': {e}")
            continue

    # Cleanup old logs
    deleted_count = cleanup_old_logs(log_path, retention_days)

    print(f"--- Summary ---")
    print(f"Logs Rotated: {rotated_count}")
    print(f"Logs Compressed: {compressed_count}")
    print(f"Old Logs Deleted: {deleted_count}")

if __name__ == "__main__":
    main()
