                },
                "required": ["code", "message"]
            }
        }
    },
    "required": ["system_name", "version", "endpoints"]
}

def load_config(file_path: str) -> Dict[str, Any]:
    """Load and parse the JSON configuration file."""
    try:
        with open(file_path, 'r', encoding='utf-8') as f:
            return json.load(f)
    except FileNotFoundError:
        print(f"Error: Configuration file '{file_path}' not found.")
        sys.exit(1)
    except json.JSONDecodeError as e:
        print(f"Error: Malformed JSON in configuration file: {e}")
        sys.exit(1)

def validate_config(config: Dict[str, Any]) -> None:
    """Validate the configuration against the predefined schema."""
    try:
        validate(instance=config, schema=CONFIG_SCHEMA)
    except ValidationError as e:
        print(f"Validation Error: {e.message}")
        sys.exit(1)
    except SchemaError as e:
        print(f"Schema Definition Error: {e.message}")
        sys.exit(1)

def generate_python_snippet(endpoint: Dict[str, Any]) -> str:
    """Generate a Python code snippet for a specific endpoint."""
    name = endpoint['name']
    method = endpoint['method']
    path = endpoint['path']
    schema = endpoint['input_schema']

    # Simple heuristic to generate example payload based on schema properties
    payload_parts = []
    if 'properties' in schema:
        for prop_name, prop_def in schema['properties'].items():
            if prop_name in schema.get('required', []):
                if prop_def.get('type') == 'array':
                    payload_parts.append(f'    "{prop_name}": [{{}}],')
                elif prop_def.get('type') == 'integer':
                    payload_parts.append(f'    "{prop_name}": 1,')
                else:
                    payload_parts.append(f'    "{prop_name}": "example_value",')

    payload_str = "{\n" + "\n".join(payload_parts) + "\n}"

    return f"""
### Endpoint: `{name}`

**Method:** `{method}`  
**Path:** `{path}`  
**Description:** {endpoint['description']}

#### Example Usage
```python
import requests

url = "http://localhost:8080{path}"
headers = {{
    "Content-Type": "application/json"
}}
payload = {payload_str}

response = requests.{method.lower()}(url, json=payload, headers=headers)

if response.status_code == 200:
    print("Success:", response.json())
else:
    print(f"Error: {{response.status_code}} - {{response.text}}")
```
"""

def generate_error_handling_section(errors: List[Dict[str, Any]]) -> str:
    """Generate the common error handling section."""
    if not errors:
        return "### Error Handling\n\nNo specific error codes defined in the configuration."

    lines = ["### Common Error Handling\n\n| HTTP Code | Description |\n|:---:|:---|\n"]
    for err in errors:
        lines.append(f"| {err['code']} | {err['message']} |\n")

    lines.append("\n#### Python Implementation Example\n")
    lines.append("""```python
def handle_api_error(response: requests.Response):
    if response.status_code == 400:
        raise ValueError("Invalid JSON structure provided.")
    elif response.status_code == 422:
        raise ValueError("Missing required fields in the request payload.")
    elif response.status_code >= 500:
        raise RuntimeError("Server encountered an unexpected error.")
    else:
        response.raise_for_status()
```
""")
    return "\n".join(lines)

def generate_markdown_guide(config: Dict[str, Any]) -> str:
    """Generate the full Markdown training guide."""
    lines = [
        f"# {config['system_name']} Training Guide",
        f"**Version:** {config['version']}",
        "",
        "## Overview",
        f"This guide provides step-by-step instructions for interacting with the {config['system_name']} API.",
        "",
        "## API Endpoints",
        ""
    ]

    for endpoint in config['endpoints']:
        lines.append(generate_python_snippet(endpoint))
        lines.append("")

    lines.append(generate_error_handling_section(config.get('common_errors', [])))

    return "\n".join(lines)

def main():
    if len(sys.argv) != 3:
        print("Usage: python guide_generator.py <config.json> <output.md>")
        sys.exit(1)

    input_file = sys.argv[1]
    output_file = sys.argv[2]

    config = load_config(input_file)
    validate_config(config)

    markdown_content = generate_markdown_guide(config)

    try:
        with open(output_file, 'w', encoding='utf-8') as f:
            f.write(markdown_content)
        print(f"Successfully generated training guide: {output_file}")
    except IOError as e:
        print(f"Error writing to output file: {e}")
        sys.exit(1)

if __name__ == "__main__":
    main()
